// lib/data/submissions.ts

export type CreatorTier = "Nano" | "Micro" | "Macro" | "Mega";
export type AIVerificationStatus = "Verified" | "Pending" | "Failed";
export type PaymentStatus = "Paid" | "Pending" | "Processing";
export type AppealOption = "None" | "Requested" | "Resolved";
export type ActionStatus = "Pending" | "Approved" | "Rejected" | "Flagged";

export interface Creator {
    name: string;
    handle: string;
    image: string;
    tier: CreatorTier;
    gender: string;
    followers: number;
    price: number;
}

export interface SubmissionData {
    id: string;
    creator: Creator;
    niche: string;
    link: string;
    aiVerificationStatus: AIVerificationStatus;
    actionStatus: ActionStatus;
    impressions: number;
    er: number; // Stored as decimal, e.g. 5.2 for 5.2%
    hashtags: string[];
    appealOption: AppealOption;
    paymentStatus: PaymentStatus;
    dateSubmitted: string;
    aiScore: number;
    platform: "Instagram" | "YouTube";
}

